from django.db import models

# --- Custom QuerySet (allows method chaining) ---
class ArticleQuerySet(models.QuerySet):
    def published(self):
        return self.filter(status='published')

    def by_author(self, author):
        return self.filter(author=author)

# --- Custom Manager ---
class ArticleManager(models.Manager):
    def get_queryset(self):
        # Default queryset now ALWAYS excludes deleted articles
        return ArticleQuerySet(self.model, using=self._db).filter(is_deleted=False)

    def published(self):
        return self.get_queryset().published()

class Article(models.Model):
    title = models.CharField(max_length=200)
    status = models.CharField(max_length=20, default='draft')
    is_deleted = models.BooleanField(default=False)

    # Replaces the default 'objects' manager
    objects = ArticleManager.from_queryset(ArticleQuerySet)()

# Usage examples (chaining works because Manager uses QuerySet):
Article.objects.published() # Only non-deleted published articles
Article.objects.published().by_author(request.user) # Chainable!
