from django.db import models
from django.utils import timezone

class SoftDeleteQuerySet(models.QuerySet):
    def delete(self):
        # Override bulk delete to also be soft
        return super().update(deleted_at=timezone.now())

class SoftDeleteManager(models.Manager):
    def get_queryset(self):
        # Default queryset hides soft-deleted records
        return SoftDeleteQuerySet(self.model, using=self._db).filter(deleted_at__isnull=True)

class Article(models.Model):
    title = models.CharField(max_length=200)
    # Null means not deleted; a timestamp means when it was deleted
    deleted_at = models.DateTimeField(null=True, blank=True, db_index=True)

    objects = SoftDeleteManager()         # Default: hides deleted
    all_objects = models.Manager()        # Admin/recovery: shows everything

    def delete(self, *args, **kwargs):
        # Override instance delete
        self.deleted_at = timezone.now()
        self.save(update_fields=['deleted_at'])

    def restore(self):
        self.deleted_at = None
        self.save(update_fields=['deleted_at'])
