from django import forms
from django.forms import formset_factory
from .models import Choice

class ChoiceForm(forms.ModelForm):
    class Meta:
        model = Choice
        fields = ['choice_text']

# Create a Formset class for 3 choices
ChoiceFormSet = formset_factory(ChoiceForm, extra=3, can_delete=True)

# views.py
def manage_choices(request, question_id):
    if request.method == 'POST':
        formset = ChoiceFormSet(request.POST, prefix='choices')
        if formset.is_valid():
            for form in formset.save(commit=False):
                form.question_id = question_id
                form.save()
            # Handle deleted forms
            for obj in formset.deleted_objects:
                obj.delete()
    else:
        formset = ChoiceFormSet(prefix='choices')

    return render(request, 'choices.html', {'formset': formset})

# In the template:
# {{ formset.management_form }}  <-- REQUIRED, must be included
# {% for form in formset %} ... {% endfor %}
