from fastapi import FastAPI, HTTPException, Request
from fastapi.responses import JSONResponse
from fastapi.exceptions import RequestValidationError

app = FastAPI()

# --- Standard HTTPException usage (business logic errors) ---
@app.get('/items/{id}')
async def get_item(id: int):
    item = db.get(id)
    if not item:
        raise HTTPException(
            status_code=404,
            detail={'error': 'item_not_found', 'id': id} # Structured error detail
        )
    return item

# --- Custom exception class ---
class InsufficientFundsError(Exception):
    def __init__(self, amount: float):
        self.amount = amount

# --- Global handler for your custom exception ---
@app.exception_handler(InsufficientFundsError)
async def insufficient_funds_handler(request: Request, exc: InsufficientFundsError):
    return JSONResponse(
        status_code=402,
        content={'error': 'insufficient_funds', 'required': exc.amount}
    )

# --- Override default RequestValidationError handler for custom format ---
@app.exception_handler(RequestValidationError)
async def validation_error_handler(request: Request, exc: RequestValidationError):
    return JSONResponse(
        status_code=422,
        content={'error': 'validation_failed', 'details': exc.errors()}
    )
